-- Enrichment marathon batch: Mopidy, Morgen, Morningfame, mosparo, Moss, Motion, motion.tools (Antragsgrün), Motivosity

-- ── Mopidy ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Mopidy is a free, open-source, extensible music server written in Python that plays music from local disk, Spotify, SoundCloud, and internet radio, controllable from MPD or web clients.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2009, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE(NULL, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Mopidy Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Mopidy is a free, open-source music server for Python that streams local files, Spotify, SoundCloud and radio. See features, setup, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Mopidy is a free and open-source, extensible music server written in Python. The project was started on December 23, 2009, when its creator conceived the idea while chatting with friend and collaborator Johannes Knutsen about building an MPD-compatible server that could play music from Spotify instead of only local files. The name 'Mopidy' is a blend of the consonants from 'MPD' (Music Player Daemon) and the vowels from 'Spotify.' Mopidy is not a commercial company but a community-driven open-source project, distributed under the Apache License 2.0, developed openly on GitHub with community support through a Discourse forum and Zulip chat. Architecturally, Mopidy runs as a backend server process on a computer, Raspberry Pi, or home server, exposing a core API over JSON-RPC (including a WebSocket-based HTTP frontend introduced around Mopidy 0.10 in 2012) that any MPD client or web client can connect to for playback control. Its defining feature is an extension system: since Easter 2013, Mopidy has supported pluggable extensions that add music sources (Spotify, SoundCloud, TuneIn internet radio, YouTube, Tidal, local files, podcasts, and more), alternative frontends, and audio output/mixer options. Popular first-party and community extensions include mopidy-spotify, mopidy-tidal, mopidy-youtube, mopidy-subidy (Subsonic/Airsonic), and mopidy-iris (a popular web client). A notable derivative project, Pi MusicBox, built by Wouter van Wijk in 2013, packaged Mopidy into a turnkey Raspberry Pi jukebox image. Mopidy has no pricing, subscriptions, or company behind it; it is entirely free to self-host on Linux, macOS, or Raspberry Pi hardware. Its target audience is technically inclined home audio enthusiasts, self-hosters, and developers who want a customizable, headless music server they fully control, rather than a polished consumer app. It competes conceptually with other self-hosted media servers such as Music Assistant, Navidrome, and MPD itself, as well as with proprietary smart-speaker ecosystems, but differentiates itself through deep extensibility, an active plugin ecosystem, and a scriptable JSON-RPC/WebSocket API that lets developers build custom web and mobile clients (such as Iris) on top of the core server. Because it requires command-line configuration and self-hosting knowledge, Mopidy is best suited to hobbyists and developers rather than non-technical consumers looking for an out-of-the-box streaming app.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '5843c8b6-d28f-4688-bb58-9b9b806ffe66';

