-- ── mosparo ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$mosparo is an open-source, self-hosted, privacy-friendly spam and bot protection system that screens web form submissions by analyzing their content instead of using CAPTCHA puzzles.$q$, short_description),
  pricing_model = COALESCE($q$Open Source$q$, pricing_model),
  starting_price = COALESCE($q$Free$q$, starting_price),
  founded_year = COALESCE(2021, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Switzerland$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$Finnish$q$]::text[],
  seo_title = COALESCE($q$mosparo Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$mosparo is a free, self-hosted, open-source CAPTCHA alternative that stops form spam using content analysis. See features, setup, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$mosparo is an open-source, self-hosted spam and bot protection system for web forms, founded in 2021 after its creators needed a privacy-respecting way to stop spam on a contact form without relying on third-party CAPTCHA services that collect user data. The project is maintained by the mosparo Association, a non-profit organization based in Switzerland, and is released under the MIT license, with source code hosted publicly on GitHub. mosparo publicly launched on Product Hunt in August 2023 after operating in open beta. Architecturally, mosparo works differently from traditional CAPTCHA systems like Google's reCAPTCHA or hCaptcha: rather than presenting visual puzzles, image challenges, or checkbox verification, it evaluates the actual content submitted through a form using a rules-based scoring system comparable to an email spam filter. It examines the text entered into form fields, plus metadata such as the source domain, IP address, user agent, and submission timing, assigning a spam score based on configurable rules; it also employs an invisible honeypot field that only bots (not human users) tend to fill in, and measures how quickly a form is completed to flag suspiciously fast (likely automated) submissions. Because it requires no puzzles, distorted text, or image selection, mosparo is fully compatible with screen readers and accessible via mouse, keyboard, or touch input, addressing a common accessibility complaint about traditional CAPTCHAs. On privacy, mosparo only processes the data a user actually enters into the form plus their IP address and user agent, encrypts submitted form data, automatically hashes IP addresses, deletes data after 14 days by default, and requires no tracking cookies, making it attractive to organizations operating under GDPR and similar privacy regulations. It integrates with common platforms and frameworks through official and community plugins, including WordPress, and its frontend widget strings are community-translated into more than 40 languages via the Weblate platform, including English, German, and Finnish among others. mosparo is entirely free to use since it must be self-hosted on the operator's own web server or hosting environment; there is no hosted SaaS tier or paid plan, making its pricing model pure open source. Its target audience is website owners, developers, and organizations who want form spam protection but are unwilling to send visitor data to third-party CAPTCHA providers such as Google, either for privacy-compliance reasons or general data-sovereignty preferences. Its main competitors and alternatives include Google reCAPTCHA, hCaptcha, Cloudflare Turnstile, and Akismet, but mosparo differentiates itself by being fully open source, self-hosted, cookie-free, and free of puzzles, targeting privacy-conscious and accessibility-focused site operators rather than aiming for the broad, cloud-hosted convenience of its commercial rivals.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'f23f15f9-2364-493f-94fb-df321638df83';

