-- ── Moss ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Moss is a European corporate card and spend management platform that combines company cards, invoice management, and accounts payable automation for small and mid-sized businesses.$q$, short_description),
  pricing_model = COALESCE($q$Freemium / Custom modular pricing$q$, pricing_model),
  starting_price = COALESCE($q$Free (up to 3 users); paid plans priced by module and transaction volume$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$201-500 employees$q$, company_size),
  headquarters = COALESCE($q$Berlin, Germany$q$, headquarters),
  languages = ARRAY[$q$English$q$, $q$German$q$, $q$French$q$, $q$Dutch$q$]::text[],
  seo_title = COALESCE($q$Moss Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Moss is a European spend management platform with corporate cards, invoicing, and approvals. Compare features, pricing plans, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Moss is a European corporate card and spend management platform founded in 2019 in Berlin, Germany, by Anton Rummel, Ante Spittler, Ferdinand Meyer, Stephan Haslebacher, and Harald Wendel. The company has grown into a Series B-stage fintech with roughly 200 to 500 employees operating across multiple European markets including the UK, Germany, the Netherlands, France, Italy, Belgium, Spain, and Austria. Moss has raised a total of approximately $148 million across five funding rounds from investors including Valar Ventures, Tiger Global Management, and Cherry Ventures, including an $86 million (about €75 million) Series B round announced in January 2022 that valued the company at roughly $573 million (€500 million). Moss reports serving more than 7,000 businesses and processing over €7 billion in annual spend. Architecturally, Moss is a cloud-based platform that issues physical and virtual corporate debit and credit cards (subject to eligibility), and layers spend controls, approval workflows, and accounting automation on top. Its core modules are Corporate Cards (unlimited physical and virtual cards with configurable spending limits), Employee Reimbursements (expense submission and approval for out-of-pocket spend), and Accounts Payable (invoice capture, approval routing, and payment processing), each priced and enabled independently so companies only pay for what they use. Optional add-ons extend the platform further, including Advanced Controlling, Procurement, ERP integrations, and AI-powered accounting automation that can auto-categorize transactions and match receipts. Moss integrates with accounting systems and HR software to keep financial data synchronized and automate month-end close. Pricing is modular rather than fixed-tier: a Free plan supports up to 3 users with unlimited cards, up to 20 invoices per month, customizable approval and verification steps, and a Moss debit wallet. Paid plans move to unlimited users and cards (no per-user fees), advanced approval flows and budget controls, accounting integrations, HR system integrations for smart user management, 1:1 onboarding support, and flexible debit or credit funding, with actual cost determined by a platform fee plus a variable fee based on monthly transaction volume (card transactions, invoices, and reimbursements combined). Moss's target audience is small and mid-sized European businesses and finance teams that need centralized control over company spending without the overhead of traditional corporate card programs or manual expense reporting. Its main competitors include Pleo, Spendesk, Payhawk, Ramp, and Brex, with Moss differentiating itself through its modular, pay-for-what-you-use pricing structure, strong presence across multiple European markets and currencies, and an integrated approach spanning cards, reimbursements, and accounts payable in one platform rather than separate point solutions.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '11cc6093-d880-4046-9b74-e055ae089a8e';

