-- ── Motion ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Motion is an AI-powered calendar, task, and project management app that automatically schedules tasks and meetings into a user's calendar to protect focus time.$q$, short_description),
  pricing_model = COALESCE($q$Subscription$q$, pricing_model),
  starting_price = COALESCE($q$$19/month (Pro AI, billed monthly)$q$, starting_price),
  founded_year = COALESCE(2019, founded_year),
  company_size = COALESCE($q$Approximately 65 employees$q$, company_size),
  headquarters = COALESCE($q$San Francisco, California, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Motion Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Motion is an AI calendar and task manager that auto-schedules your day. Compare its features, pricing plans, pros, cons, and top alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Motion (usemotion.com) is an AI-powered work management platform founded in 2019 by Harry Qi (CEO), Omid Rooholfada, and Ethan Yu, headquartered in San Francisco, California. The company went through Y Combinator and has raised roughly $75 million in total funding across Series B, C, and C2 rounds, including a Series C round in 2024 led by Leonis Capital, reaching a valuation of around $550 million and reporting approximately $10 million in annual revenue by 2025, up from about $2 million the year prior, serving more than 100,000 customers. The company employs roughly 65 people. Motion's core product is an AI scheduling engine that sits on top of a user's existing calendar (Google Calendar or Outlook) and task list: rather than requiring users to manually block time, Motion's algorithm automatically places tasks, meetings, and to-dos into open calendar time based on deadlines, priorities, estimated durations, and existing commitments, then dynamically re-shuffles the schedule in real time as new events, cancellations, or overruns occur throughout the day. Beyond personal scheduling, Motion has expanded into a broader 'agentic work suite' encompassing project management (boards, timelines), task management, docs and wiki functionality, meeting scheduling links (a Calendly-style booking tool), reporting, and, more recently, AI agents intended to autonomously execute parts of workflows rather than just schedule them, positioning Motion as combining calendar automation with project-management-suite functionality. Pricing has no permanent free tier; Motion offers a 7-day free trial on both paid tiers. The Pro AI plan costs $19/month (about $12.73/month billed annually) for individuals, and the Business AI plan costs $29 per seat/month (about $19.43/seat/month billed annually) for teams needing shared projects and collaborative scheduling. Motion's target audience is busy professionals, founders, consultants, freelancers, and small-to-mid-sized teams who struggle to protect focus time amid frequent meetings and shifting priorities, as well as agencies and teams wanting combined project management and AI scheduling in one tool. Its main competitors include Reclaim.ai and Clockwise (AI calendar scheduling), Sunsama (daily planning), Asana, ClickUp, and Monday.com (project management), and Morgen (calendar unification with scheduling links). Motion differentiates itself through its fully automated, algorithm-driven scheduling (rather than manual time-blocking) combined with an expanding project-management and AI-agent feature set, aiming to be a single AI-native workspace rather than a narrow scheduling add-on.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'bf92d64e-0be1-4ba9-986c-37463bbdbdeb';

