-- ── motion.tools (Antragsgrün) ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$motion.tools, also known as Antragsgrün, is open-source software for managing motions, amendments, and candidacies at conferences and assemblies for political parties, unions, and NGOs.$q$, short_description),
  pricing_model = COALESCE($q$Open Source (paid hosting and support optional)$q$, pricing_model),
  starting_price = COALESCE($q$Free (self-hosted); paid hosting and support available on an hourly basis$q$, starting_price),
  founded_year = COALESCE(2012, founded_year),
  company_size = COALESCE(NULL, company_size),
  headquarters = COALESCE($q$Germany$q$, headquarters),
  languages = ARRAY[$q$German$q$, $q$English$q$, $q$French$q$]::text[],
  seo_title = COALESCE($q$motion.tools (Antragsgrün) Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$motion.tools (Antragsgrün) manages motions, amendments, and votes for parties and NGOs. See features, hosting options, pricing, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$motion.tools, known in German as Antragsgrün, is open-source software for managing motions, amendments, and candidacies at conferences and general assemblies. It was originally created in 2012 by developer Tobias Hößl for the Bavarian state branch of Alliance 90/The Greens to simplify motion management at state delegate conferences, with the first version already supporting motion submission, amendments, comments, and automatically generated PDF exports. As other regional and national Green Party branches adopted the tool, the original single-instance-per-organization model didn't scale, prompting the development of Antragsgrün 2 with multi-tenancy, allowing one central installation to serve many separate organizations. The software has continued through major version releases since (recent versions in the 4.x series, such as 4.14 through 4.17), and is licensed under the AGPL open-source license, with source code publicly available on GitHub under CatoTH/antragsgruen. Antragsgrün has been used at political conventions and organizational assemblies for more than a decade, by organizations including the European Youth Forum, the German and European Green Party, Volt Europa, and the National Council of German Women's Organizations, supporting groups ranging from small informal working groups to large general assemblies with hundreds of delegates and thousands of amendments. Functionally, the platform manages the full lifecycle of a motion: submission and publishing of motions, amendments, and candidacies; commenting and collaborative discussion; automated document generation with customizable print/export templates (PDF, spreadsheet, plain text); merging of accepted amendments into final consolidated documents; and on-site convention support tools including agendas, speaking lists, roll calls, live voting, and a full-screen projector display mode for use during in-person sessions. Administrative features include email notifications, customizable submission policies and layouts, and single sign-on integration for larger organizations. The platform is available in German, English, and French. Because it is open source, Antragsgrün can be downloaded and self-hosted for free on any organization's own servers; the project also offers optional professional services, including hosting, support, and custom feature development, billed on an hourly rate basis, and prospective users can spin up a temporary test instance without providing contact details to trial the platform. Privacy is emphasized, with no trackers used and servers hosted primarily within the EU, with US hosting available on request for organizations that need it. Its target audience is political parties, NGOs, unions, and other membership organizations that run formal motion and amendment processes at conferences or assemblies. It is functionally distinct from generic meeting or voting software and from unrelated products that also use the word 'motion' in their name, such as the AI calendar app usemotion.com or the motion.dev JavaScript animation library; competitors in its actual space include other convention/motion-management tools and custom-built internal systems used by large political organizations.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = '2c846e33-a0ef-4fe5-b290-203fbdef22b6';

