-- ── Motivosity ──────────────────────────────────────────────
UPDATE tools SET
  short_description = COALESCE($q$Motivosity is an employee recognition and engagement platform that lets coworkers give peer-to-peer recognition tied to monetary rewards, alongside surveys and HR program tools.$q$, short_description),
  pricing_model = COALESCE($q$Custom / Per-employee subscription$q$, pricing_model),
  starting_price = COALESCE($q$Custom pricing, contact sales$q$, starting_price),
  founded_year = COALESCE(2013, founded_year),
  company_size = COALESCE($q$80+ employees$q$, company_size),
  headquarters = COALESCE($q$Lehi, Utah, United States$q$, headquarters),
  languages = ARRAY[$q$English$q$]::text[],
  seo_title = COALESCE($q$Motivosity Review 2026: Features, Pricing and Alternatives$q$, seo_title),
  seo_meta_description = COALESCE($q$Motivosity is an employee recognition platform with peer rewards, surveys, and HR programs. Compare features, pricing, pros, cons, and alternatives.$q$, seo_meta_description),
  llm_readable_summary = COALESCE($q$Motivosity is an employee recognition and engagement platform founded in 2013 by Scott Johnson and headquartered in Lehi, Utah. The company has grown to more than 80 employees and was reported to generate an estimated $16.9 million in revenue as of 2025, having been recognized on the Inc. 5000 list of fastest-growing private US companies for multiple years. The platform is built around peer-to-peer recognition: employees give each other public recognition tied to small monetary amounts drawn from individual or company-funded budgets, which recipients can redeem for gift cards, charitable donations, company swag, or other rewards, aiming to make recognition feel tangible rather than purely symbolic. Beyond recognition, Motivosity has expanded into a broader people/HR platform, offering tools for employee surveys and pulse feedback to measure engagement and sentiment, one-on-one meeting and manager coaching tools, company-wide announcements and social recognition feeds, service anniversary and milestone celebrations, and administration for running multiple HR programs (such as wellness initiatives or company swag stores) from one place. The product is typically deployed company-wide and integrates with existing HR information systems (HRIS), Slack, and Microsoft Teams so recognition can happen inside tools employees already use. Pricing is fully custom and not published on Motivosity's website; prospective customers must contact sales for a quote, with pricing generally structured per employee per month and varying based on company size and which modules (recognition, surveys, HR programs) are enabled. Motivosity's target audience is mid-sized to large companies, particularly HR and people-operations teams, looking to reduce turnover and improve employee engagement through structured recognition programs backed by measurable spending data and survey analytics. Its main competitors include Bonusly, Nectar, Kudos, Achievers, and Workhuman, all of which offer similar peer-recognition-plus-rewards models. Motivosity differentiates itself through its emphasis on peer-driven (rather than only manager-driven) recognition, transparent visibility into recognition activity across the organization, and its expansion beyond pure recognition into a fuller suite of employee engagement and HR program tools.$q$, llm_readable_summary),
  status = 'published',
  noindex = false,
  sitemap_eligible = true,
  published_at = COALESCE(published_at, now()),
  updated_at = now()
WHERE id = 'abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814';

