INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Extension system$q$, $q$Pluggable Python extensions add new music sources, frontends, and audio outputs without touching the Mopidy core.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$MPD protocol support$q$, $q$Works with the large existing library of MPD clients on desktop, mobile, and command line.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$HTTP and JSON-RPC API$q$, $q$A WebSocket-based JSON-RPC API exposes the full core API for building custom web and app clients.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Streaming service extensions$q$, $q$Community and first-party extensions connect Spotify, Tidal, SoundCloud, TuneIn radio, YouTube and more.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Local file library support$q$, $q$Indexes and streams music stored on local disk alongside streaming sources in one unified library.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Raspberry Pi friendly$q$, $q$Lightweight enough to run continuously on low-power hardware like a Raspberry Pi for always-on home audio.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Cross-platform$q$, $q$Runs on Linux, macOS, and other platforms supporting Python and GStreamer.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Community web clients$q$, $q$Third-party web UIs such as Iris provide a full graphical browser interface on top of Mopidy's API.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Completely free and open source with no subscription cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Highly extensible via a mature plugin ecosystem$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Works with existing MPD clients as well as modern web clients$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Runs well on inexpensive, low-power hardware like Raspberry Pi$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Active community with over a decade of continuous development$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Requires command-line setup and configuration file editing, not beginner friendly$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$No official polished mobile app; relies on third-party or community clients$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Streaming extensions depend on third-party services' unofficial APIs, which can break$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$No commercial support or SLA since it is a volunteer-run project$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Initial setup and extension installation can be technically demanding for non-developers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Is Mopidy free to use?$q$, $q$Yes. Mopidy is fully open source under the Apache License 2.0 and free to download, install, and run with no subscription fees.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Can Mopidy play Spotify and other streaming services?$q$, $q$Yes, through official and community-maintained extensions such as mopidy-spotify and mopidy-tidal, though these typically require an active paid subscription to the underlying streaming service.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Do I need a Raspberry Pi to run Mopidy?$q$, $q$No, Mopidy runs on any Linux or macOS machine, but it is popular on Raspberry Pi because of its low power consumption and always-on convenience.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$What clients can control Mopidy?$q$, $q$Any MPD-compatible client, plus web clients like Iris that use Mopidy's HTTP/JSON-RPC/WebSocket API.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Is Mopidy suitable for non-technical users?$q$, $q$Not particularly. Mopidy requires configuration file editing and command-line familiarity, making it best suited to hobbyists and developers.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Who maintains Mopidy?$q$, $q$Mopidy is a community-driven open-source project developed openly on GitHub, not a commercial company.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Whole-home audio server$q$, $q$Run Mopidy on a Raspberry Pi or home server to stream local files and Spotify/Tidal to speakers throughout the house via MPD or web clients.$q$, $q$Home audio hobbyists$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Custom music app backend$q$, $q$Developers build bespoke web or mobile music player interfaces on top of Mopidy's JSON-RPC/WebSocket API.$q$, $q$Developers and self-hosters$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Unified library across streaming services$q$, $q$Combine local files with Spotify, SoundCloud, and internet radio into a single browsable library and playlist system.$q$, $q$Music enthusiasts with multiple streaming subscriptions$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full Mopidy core server","All official and community extensions","Apache 2.0 licensed source code","Community support via Discourse and Zulip"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Mopidy is an open-source, extensible music server written in Python that lets you play music from local disk, Spotify, SoundCloud, internet radio and other sources through a single unified backend. Rather than being a desktop or mobile app itself, Mopidy runs as a headless server process that exposes a control API, letting any MPD-compatible client or web client connect to browse and play music remotely.$q$, $q$The project began in December 2009 as an experiment in combining the classic Music Player Daemon (MPD) protocol with the ability to stream from Spotify. Over more than a decade of community development it has grown into a modular platform with a large ecosystem of third-party extensions, commonly deployed on Raspberry Pi devices, home servers, and always-on Linux boxes to create a whole-home or single-room music hub.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Mopidy's core strength is its extension architecture: separate Python packages can be installed to add new music sources (Spotify, Tidal, SoundCloud, TuneIn, YouTube, podcasts, local libraries), new frontends (an HTTP/JSON-RPC/WebSocket API, MPD protocol support, Last.fm scrobbling), and new audio backends, all without modifying Mopidy's core.$q$, $q$Because it speaks the MPD protocol, Mopidy works out of the box with the large existing ecosystem of MPD clients on desktop, mobile, and web. Its own HTTP/JSON-RPC frontend also powers community-built web clients such as Iris, which provide a modern browser-based interface for controlling playback, browsing libraries, and managing playlists across all connected sources from one screen.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Mopidy itself is completely free and open source under the Apache License 2.0, with no paid tiers, subscriptions, or commercial edition. There is no company monetizing Mopidy directly.$q$, $q$Any costs involved come from what you run it on (a Raspberry Pi or server) and from the underlying music services you connect through extensions, such as a paid Spotify Premium or Tidal subscription, which those third-party streaming services require for API playback.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('5843c8b6-d28f-4688-bb58-9b9b806ffe66', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Multi-calendar unification$q$, $q$Connects Google, Outlook/Office 365, and iCloud calendars into one merged view.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Scheduling links and booking pages$q$, $q$Calendly-style booking pages and one-time or recurring scheduling links based on real combined availability.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Task manager integrations$q$, $q$Pulls tasks from Todoist, Notion, ClickUp, Asana, and Linear directly into the calendar view.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Time blocking$q$, $q$Drag-and-drop tasks onto the calendar to visually plan and protect time for deep work.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Virtual meeting integrations$q$, $q$Automatically attaches Zoom, Google Meet, or Microsoft Teams links to scheduled meetings.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Cross-platform apps$q$, $q$Native apps for macOS, Windows, Linux, iOS, Android, and a web client.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Command-bar quick add$q$, $q$Keyboard-driven quick entry for creating events and tasks without leaving the keyboard.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Team scheduling$q$, $q$Shared availability and booking features for teams on the Team plan.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Generous free plan with unlimited scheduling links and tasks$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$True cross-platform support including Linux, unlike many calendar apps$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Combines calendar unification, task management, and scheduling links in one app$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Clean, fast, keyboard-friendly interface$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Integrates with major task managers rather than forcing a new one$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Free plan limited to a single connected calendar account$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Pro pricing is relatively high for individual users compared to single-purpose scheduling tools$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Smaller company than major competitors, so long-term roadmap depends on a small team$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Some advanced automation features lag behind AI-first competitors like Motion or Reclaim$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Team collaboration features are less mature than dedicated team scheduling tools$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$What calendars does Morgen support?$q$, $q$Morgen connects to Google Calendar, Microsoft Outlook/Office 365, and Apple iCloud, merging them into a single unified view.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Is Morgen free?$q$, $q$Yes, Morgen has a free plan with one connected calendar account, unlimited scheduling links and tasks, and a personal booking page; paid Pro and Team plans unlock more accounts and features.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Does Morgen replace my existing calendar app?$q$, $q$No, Morgen syncs with your existing calendar providers rather than replacing them, so events stay in sync with Google, Outlook, or iCloud.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Can Morgen manage tasks as well as events?$q$, $q$Yes, Morgen integrates with task managers like Todoist, Notion, ClickUp, Asana, and Linear and lets you time-block tasks directly on your calendar.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Does Morgen offer scheduling links like Calendly?$q$, $q$Yes, Morgen includes a personal booking page and both recurring and one-time scheduling links based on your combined calendar availability.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$What platforms does Morgen run on?$q$, $q$Morgen has native apps for macOS, Windows, Linux, iOS, and Android, plus a web app.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Managing work and personal calendars together$q$, $q$Professionals with separate work Outlook and personal Gmail calendars use Morgen to see and plan around both in one view.$q$, $q$Knowledge workers and consultants$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Client and meeting scheduling$q$, $q$Founders and freelancers share a Morgen booking page so clients can self-schedule meetings based on real availability.$q$, $q$Freelancers, consultants, founders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Team availability coordination$q$, $q$Small teams use Morgen's Team plan to coordinate shared scheduling links and see combined availability.$q$, $q$Small teams and startups$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["1 connected calendar account","Unlimited calendar subscriptions","Personal booking page","1 recurring scheduling link","Unlimited one-time scheduling links","Unlimited tasks and task lists"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Pro$q$, $q$$30/month or $15/month billed annually$q$, $q$Monthly or annual$q$, NULL, $q$["Multiple connected calendar accounts","Expanded scheduling links","Deeper task app integrations","Time blocking tools"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$Team$q$, $q$$25/month or $10/month billed annually per seat$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Pro","Shared team scheduling","Team availability views"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Morgen is a cross-platform calendar app founded in 2021 in Zurich, Switzerland, built to solve the problem of juggling multiple calendar accounts across Google, Outlook, and iCloud. Rather than replacing your existing calendar provider, Morgen syncs with them and layers a unified view, time-blocking tools, task integrations, and scheduling links on top.$q$, $q$The app is positioned as a universal time-management hub: alongside events synced from connected calendars, it pulls in tasks from tools like Todoist, Notion, ClickUp, Asana and Linear so users can plan their day by dragging tasks directly onto their calendar timeline.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Morgen's scheduling-link system lets external contacts book meetings against a user's real-time combined availability, similar to Calendly, with support for both recurring booking pages and one-off scheduling links. Virtual meeting integrations with Zoom, Google Meet and Microsoft Teams automatically attach conferencing details to booked events.$q$, $q$Time blocking is a central workflow: users can drag tasks from integrated task managers onto open calendar time to visually plan their day, and Morgen supports native apps across macOS, Windows, Linux, iOS, Android, and the web so the experience is consistent regardless of platform.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f44a5433-17b4-408d-9f04-3a38418faa5d', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Morgen offers a genuinely usable Free plan covering one connected calendar account, unlimited calendar subscriptions, a personal booking page, one recurring scheduling link, unlimited one-time links, and unlimited tasks.$q$, $q$The Pro plan costs roughly $30/month paid monthly or about $15/month billed annually, unlocking multiple calendar accounts and expanded scheduling and task-integration limits. A Team plan (around $25/month, or $10/month billed annually per seat) adds shared scheduling for teams. New subscribers get a 14-day free trial and a 30-day money-back guarantee.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Keyword and topic research$q$, $q$Suggests video topics based on estimated YouTube search volume and competition.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Channel analytics dashboard$q$, $q$Summarizes channel-level trends in views, watch time, and subscriber growth.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Video-level performance analysis$q$, $q$Breaks down individual video metrics like click-through rate and audience retention.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Content planning tools$q$, $q$Helps creators plan upcoming uploads around identified keyword opportunities.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Competition scoring$q$, $q$Rates how competitive a given keyword or topic is before a creator commits to it.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Affordable entry pricing$q$, $q$Priced lower than many competitors to be accessible to hobbyist and part-time creators.$q$, 5);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Significantly cheaper than TubeBuddy and VidIQ's comparable tiers$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Focused, easy-to-understand interface aimed at smaller creators$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Keyword research grounded in actual YouTube search data$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Simple two-tier pricing without confusing add-ons$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Encourages a batch content-planning workflow with the Basic plan's 12-day cycle$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$No permanent free plan, only a free first month$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Basic plan's keyword tool is rate-limited to a recurring 24-hour window$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Fewer bundled features than larger competitors, such as thumbnail A/B testing or bulk editing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Smaller company with a lean team, so feature velocity is slower than larger rivals$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Primarily useful for small-to-mid channels; less differentiated value for very large channels or agencies$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$What is Morningfame used for?$q$, $q$Morningfame is a YouTube analytics and keyword research tool that helps creators find video topics with real search demand and track channel and video performance.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$How much does Morningfame cost?$q$, $q$Morningfame's Basic plan starts at $4.90/month and the Plus plan is $12.90/month, both cheaper when billed annually; there is no permanent free plan but new users typically get a free first month.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$What is the difference between Morningfame Basic and Plus?$q$, $q$Basic includes full analytics access but limits the keyword research tool to a recurring 24-hour window roughly every 12 days, while Plus removes that limit for unlimited daily keyword research.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$How is Morningfame different from TubeBuddy or VidIQ?$q$, $q$Morningfame focuses more narrowly on keyword research and analytics at a lower price point, while TubeBuddy and VidIQ bundle a wider set of features like thumbnail testing and bulk editing tools.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Who founded Morningfame?$q$, $q$Morningfame was founded in 2014 by Nico Kamenzky in Germany.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Does Morningfame work for small YouTube channels?$q$, $q$Yes, Morningfame is specifically designed to be accessible and useful for small and mid-sized channels, not just large creators or agencies.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Keyword-driven video planning$q$, $q$Creators use Morningfame's keyword tool to identify topics with search demand before scripting and filming videos.$q$, $q$Individual YouTube creators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Tracking channel growth$q$, $q$Creators monitor view, watch-time, and subscriber trends over time to understand what content resonates.$q$, $q$Growing YouTube channels$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Budget-conscious channel optimization$q$, $q$Smaller creators who cannot justify TubeBuddy or VidIQ's pricier tiers use Morningfame as an affordable alternative.$q$, $q$Hobbyist and part-time YouTubers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Basic$q$, $q$$4.90/month (or $46.80/year, about $3.90/month)$q$, $q$Monthly or annual$q$, NULL, $q$["Full analytics access","Keyword tool unlocked for 24 hours roughly every 12 days","Video and channel performance tracking"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$Plus$q$, $q$$12.90/month (or $118.80/year, about $9.90/month)$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Basic","Unlimited daily keyword research tool access","No usage restrictions on keyword planning"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Morningfame is a YouTube analytics and keyword research platform founded in 2014 by Nico Kamenzky in Germany. It was built to give small and growing YouTube channels access to the kind of keyword and performance data that larger creators and agencies typically pay much more for through competing tools.$q$, $q$The platform connects directly to a creator's YouTube channel and combines standard analytics (views, watch time, click-through rate, retention) with a proprietary keyword research engine that estimates search demand and competition for potential video topics.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Morningfame's keyword research tool suggests topic ideas based on estimated YouTube search volume and competition, helping creators choose titles and topics more likely to be discovered through search and suggested video placement.$q$, $q$Its analytics dashboards break down channel and video performance to highlight what's working, while content planning features help creators map out an upload schedule based on keyword opportunities identified during research sessions.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bac1828c-1e04-4f20-976c-9a0ea0ed8e67', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Morningfame offers two paid tiers with no permanent free plan, though new signups typically get a free first month. The Basic plan is $4.90/month (or about $3.90/month, $46.80/year, billed annually) and includes full analytics with time-limited keyword tool access roughly every 12 days.$q$, $q$The Plus plan is $12.90/month (or about $9.90/month, $118.80/year, billed annually) and removes the keyword tool's usage restrictions entirely, giving unlimited daily access for creators who plan content more frequently.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Content-based spam scoring$q$, $q$Analyzes submitted form text against configurable rules to flag likely spam, similar to an email spam filter.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Honeypot field detection$q$, $q$Uses an invisible field that only bots fill in to catch automated submissions.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Submission timing analysis$q$, $q$Flags forms completed suspiciously fast as likely automated.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$No puzzles or CAPTCHA challenges$q$, $q$Verifies submissions without image selection, distorted text, or checkboxes.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Full accessibility support$q$, $q$Fully compatible with screen readers and usable via mouse, keyboard, or touch.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Privacy-first data handling$q$, $q$Uses only submitted data, IP, and user agent; encrypts data, hashes IPs, and auto-deletes after 14 days.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$No tracking cookies$q$, $q$Operates without setting any cookies, avoiding cookie-consent requirements tied to third-party CAPTCHAs.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Self-hosted and open source$q$, $q$Fully self-hosted under the MIT license, giving operators complete control over data and infrastructure.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Completely free and open source with no paid tier$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Fully self-hosted, keeping visitor data off third-party servers$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$No cookies required, simplifying GDPR/privacy compliance$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Fully accessible with no CAPTCHA puzzles or image challenges$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Non-profit governance rather than a commercial vendor collecting user data$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Requires self-hosting and technical setup, unlike plug-and-play SaaS CAPTCHAs$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$No official managed cloud hosting option from the project itself$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Smaller ecosystem and community than Google reCAPTCHA or hCaptcha$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Effectiveness depends on properly configured spam-scoring rules$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Fewer third-party platform integrations than more established CAPTCHA providers$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Is mosparo really free?$q$, $q$Yes, mosparo is fully open source under the MIT license with no paid plans; it must be self-hosted on your own server.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$How does mosparo detect spam without CAPTCHA puzzles?$q$, $q$It analyzes the actual content submitted through a form using configurable spam-scoring rules, plus a honeypot field and submission-timing checks to catch bots.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Does mosparo use cookies?$q$, $q$No, mosparo does not use tracking cookies and only processes the data a user enters into the form, their IP address, and user agent.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Who maintains mosparo?$q$, $q$mosparo is maintained by the mosparo Association, a non-profit organization based in Switzerland, with development happening openly on GitHub.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Is mosparo accessible for users with disabilities?$q$, $q$Yes, since it has no visual puzzles or image challenges, it is fully compatible with screen readers and works with mouse, keyboard, or touch input.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$What platforms does mosparo integrate with?$q$, $q$mosparo offers official and community plugins for platforms including WordPress, alongside a general API for custom integrations.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Privacy-compliant contact form protection$q$, $q$Organizations subject to GDPR use mosparo to block form spam without sending visitor data to third-party CAPTCHA vendors.$q$, $q$EU-based website operators$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Accessible form protection$q$, $q$Sites prioritizing accessibility use mosparo to avoid CAPTCHA puzzles that are difficult for screen-reader users.$q$, $q$Accessibility-focused organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Self-hosted infrastructure environments$q$, $q$Developers who avoid third-party cloud dependencies deploy mosparo alongside their own self-hosted stack.$q$, $q$Self-hosting developers and agencies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Self-hosted installation","Content-based spam scoring","Honeypot and timing detection","WordPress and platform plugins","Community translations in 40+ languages"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$mosparo is an open-source, self-hosted alternative to CAPTCHA that protects web forms from spam by analyzing submitted content rather than forcing users through visual puzzles. Founded in 2021 and maintained by the Swiss non-profit mosparo Association, it is released under the MIT license with source code publicly available on GitHub.$q$, $q$Instead of relying on a third-party service like Google reCAPTCHA, mosparo runs entirely on infrastructure the site owner controls, evaluating form submissions using rule-based content scoring, a honeypot field, and submission-timing analysis.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$mosparo scores submitted form content against configurable spam rules, similar to how an email spam filter works, while an invisible honeypot field and timing analysis catch automated bot submissions that never see the honeypot or that fill forms too quickly to be human.$q$, $q$Because there are no puzzles, distorted text, or image challenges, mosparo is fully accessible via screen readers, keyboard, mouse, or touch. It also avoids tracking cookies, encrypts stored form data, hashes IP addresses, and deletes data automatically after 14 days by default.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$mosparo is completely free and open source under the MIT license. There is no hosted SaaS product or paid tier; site operators install and run mosparo on their own web hosting.$q$, $q$Because it must be self-hosted, the only real cost is the operator's own server or hosting infrastructure, making it effectively free for anyone already running a website with standard hosting.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('f23f15f9-2364-493f-94fb-df321638df83', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Unlimited corporate cards$q$, $q$Issues unlimited physical and virtual debit or credit cards with configurable per-card spending limits.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Customizable approval workflows$q$, $q$Configurable multi-step approval and verification rules for spending requests and invoices.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Accounts payable automation$q$, $q$Captures, routes, and processes invoices for approval and payment in one workflow.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Employee reimbursements$q$, $q$Streamlines out-of-pocket expense submission and reimbursement for employees.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Accounting and HR integrations$q$, $q$Syncs transaction and approval data with accounting platforms and HR software.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$AI-powered accounting add-on$q$, $q$Optional AI features that auto-categorize transactions and match receipts.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Budget and controlling tools$q$, $q$Advanced Controlling add-on gives finance teams granular budget tracking across departments.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Modular, pay-for-what-you-use pricing$q$, $q$Companies enable and pay only for the specific modules (cards, reimbursements, AP) they need.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Modular pricing means companies only pay for modules they actually use$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$No per-user fees, so unlimited users and cards on paid plans$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Combines corporate cards, invoicing, and reimbursements in one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Strong European market coverage across multiple countries and currencies$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Well-capitalized with backing from major investors including Tiger Global$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Pricing is not fully transparent online since it is quote-based and modular$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Primarily focused on European markets, less suited to non-European businesses$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Card issuance eligibility (debit vs credit) varies by company and region$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Free plan invoice limit (20/month) may be restrictive for growing businesses$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Advanced features like ERP integrations require paid add-ons$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$What does Moss do?$q$, $q$Moss is a European spend management platform offering corporate cards, invoice management (accounts payable), and employee reimbursements in one system.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$How much does Moss cost?$q$, $q$Moss has a free plan for up to 3 users, unlimited cards, and 20 invoices per month. Paid plans use modular pricing based on a platform fee plus a variable fee tied to monthly transaction volume.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Where is Moss based?$q$, $q$Moss is headquartered in Berlin, Germany, and operates across multiple European markets including the UK, Netherlands, France, Italy, Belgium, Spain, and Austria.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Who founded Moss?$q$, $q$Moss was founded in 2019 by Anton Rummel, Ante Spittler, Ferdinand Meyer, Stephan Haslebacher, and Harald Wendel.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Does Moss charge per user?$q$, $q$No, Moss does not charge per-user fees on its paid plans; pricing is based on modules enabled and transaction volume instead.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$What are Moss's main competitors?$q$, $q$Moss competes with other European spend management platforms such as Pleo, Spendesk, and Payhawk, as well as global players like Ramp and Brex.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Centralizing company card spend$q$, $q$Finance teams issue unlimited virtual and physical cards with spend limits to replace scattered personal reimbursements.$q$, $q$SME finance teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Automating accounts payable$q$, $q$Companies route vendor invoices through configurable approval workflows to speed up payment and reduce manual entry.$q$, $q$Growing European businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Streamlining employee reimbursements$q$, $q$Employees submit out-of-pocket expenses through Moss for faster, tracked reimbursement.$q$, $q$Distributed or travel-heavy teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Free$q$, $q$$0$q$, $q$N/A$q$, NULL, $q$["Up to 3 users with unlimited cards","Up to 20 invoices per month","Customizable approval and verification steps","Moss debit wallet"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$Paid (modular)$q$, $q$Custom, platform fee plus variable transaction-based fee$q$, $q$Monthly$q$, NULL, $q$["Unlimited users and cards","Advanced approval flows and budget controls","Accounting and HR integrations","1:1 onboarding support","Debit or credit funding options"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Moss is a Berlin-based spend management platform founded in 2019 that gives European businesses corporate cards, invoice management, and employee reimbursements in a single system. The company has raised roughly $148 million from investors including Valar Ventures, Tiger Global, and Cherry Ventures, reaching a valuation of about $573 million after its Series B round.$q$, $q$Moss operates across multiple European markets, including Germany, the UK, the Netherlands, France, Italy, Belgium, Spain, and Austria, serving more than 7,000 businesses and processing over €7 billion in annual spend as of its most recent public figures.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Moss issues unlimited physical and virtual corporate debit and credit cards with configurable spending limits and approval rules, giving finance teams real-time visibility and control over company-wide spend without manual expense reports.$q$, $q$Beyond cards, Moss automates accounts payable (invoice capture and approval routing) and employee reimbursements, and connects to accounting and HR systems so transactions, receipts, and approvals sync automatically, reducing manual month-end close work.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('11cc6093-d880-4046-9b74-e055ae089a8e', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Moss offers a Free plan for up to 3 users with unlimited cards, up to 20 invoices per month, and a Moss debit wallet. Paid plans remove user limits and add advanced approval flows, accounting integrations, and flexible funding.$q$, $q$Rather than fixed subscription tiers, Moss uses modular pricing built from a platform fee plus a variable fee tied to monthly transaction volume across cards, invoices, and reimbursements, with optional add-on modules like Advanced Controlling, Procurement, and ERP integrations priced separately.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$AI auto-scheduling$q$, $q$Automatically places tasks and to-dos into open calendar time based on deadlines and priorities.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Dynamic re-planning$q$, $q$Re-shuffles the day's schedule in real time as meetings run over or new items are added.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Project management boards$q$, $q$Kanban-style boards and timelines for managing team projects alongside individual scheduling.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Meeting scheduling links$q$, $q$Calendly-style booking pages that let others schedule meetings based on real availability.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Calendar sync$q$, $q$Syncs with Google Calendar and Outlook to reflect and manage existing commitments.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Task priority and duration estimation$q$, $q$Users set priority levels and estimated durations that the AI uses to sequence work.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$AI agents$q$, $q$Emerging agentic features intended to autonomously execute parts of workflows.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Reporting and analytics$q$, $q$Tracks how time is actually spent versus planned across tasks and projects.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Fully automated scheduling removes manual time-blocking effort$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Combines calendar automation with project management in one tool$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Backed by significant funding, suggesting continued development$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Dynamic re-planning adapts the schedule as the day changes$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Meeting scheduling links reduce need for separate Calendly-style tools$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$No free plan, only a 7-day trial$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Pricing is higher than single-purpose calendar or task apps$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Automated scheduling can feel rigid for users who prefer manual control$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Learning curve to trust and configure the AI scheduling correctly$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Newer agentic work-suite features are less mature than its core scheduling$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$What does Motion do?$q$, $q$Motion is an AI-powered app that automatically schedules tasks, meetings, and to-dos into a user's calendar based on deadlines and priorities, and has expanded into broader project management.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$How much does Motion cost?$q$, $q$Motion's Pro AI plan is $19/month ($12.73/month billed annually) and Business AI is $29/seat/month ($19.43/seat/month billed annually); there is no free plan, only a 7-day trial.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Is Motion the same as the motion.dev animation library?$q$, $q$No, Motion (usemotion.com) is an unrelated AI calendar and project management app; motion.dev is a separate JavaScript animation library.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Who founded Motion?$q$, $q$Motion was founded in 2019 by Harry Qi, Omid Rooholfada, and Ethan Yu, and went through Y Combinator.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$What calendars does Motion sync with?$q$, $q$Motion syncs with Google Calendar and Microsoft Outlook to schedule tasks around existing commitments.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Who is Motion best suited for?$q$, $q$Motion is best suited for busy professionals, founders, consultants, and small-to-mid-sized teams who want automated time-blocking and combined project management.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Automated daily planning$q$, $q$Individuals let Motion auto-schedule tasks around meetings so they don't have to manually time-block each day.$q$, $q$Busy professionals and founders$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Team project and task management$q$, $q$Small teams use Motion's project boards and timelines alongside AI scheduling for shared work.$q$, $q$Small-to-mid-sized teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Client meeting scheduling$q$, $q$Consultants and freelancers share Motion booking links so clients can schedule meetings based on real availability.$q$, $q$Freelancers and consultants$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Pro AI$q$, $q$$19/month or $12.73/month billed annually$q$, $q$Monthly or annual$q$, NULL, $q$["AI auto-scheduling","Calendar sync with Google and Outlook","Task management","Meeting scheduling links"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$Business AI$q$, $q$$29/seat/month or $19.43/seat/month billed annually$q$, $q$Monthly or annual$q$, NULL, $q$["Everything in Pro AI","Team project management","Shared scheduling and collaboration","Reporting and analytics"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Motion is an AI-powered calendar, task, and project management platform founded in 2019 by Harry Qi, Omid Rooholfada, and Ethan Yu, headquartered in San Francisco and backed by Y Combinator. The company has raised about $75 million in funding and reached a $550 million valuation, growing revenue to roughly $10 million by 2025.$q$, $q$Motion's defining feature is automated scheduling: instead of manually time-blocking a calendar, users add tasks with deadlines and priorities, and Motion's algorithm automatically places them into open time on the user's existing Google or Outlook calendar, adjusting the plan throughout the day as circumstances change.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Beyond individual scheduling, Motion has expanded into a fuller work-management suite with project boards, timelines, docs, meeting scheduling links, and reporting, aiming to combine AI calendar automation with the functionality of tools like Asana or ClickUp.$q$, $q$More recently, Motion has introduced AI agent capabilities intended to autonomously execute portions of a workflow, branding the product as an 'agentic work suite' for both human and AI 'employees' rather than a narrow scheduling assistant.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('bf92d64e-0be1-4ba9-986c-37463bbdbdeb', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Motion has no permanent free plan but offers a 7-day free trial on all paid tiers. Pro AI is $19/month ($12.73/month billed annually) for individual scheduling and task management.$q$, $q$Business AI costs $29 per seat/month ($19.43/seat/month billed annually) and adds team project management, shared scheduling, and collaboration features aimed at small-to-mid-sized teams.$q$]::text[], 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Motion and amendment submission$q$, $q$Structured workflow for submitting, publishing, and discussing motions and amendments.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Candidacy management$q$, $q$Manages candidate submissions and elections alongside motions at assemblies.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Automated document generation$q$, $q$Generates customizable PDF, spreadsheet, and text exports from submitted content.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Amendment merging$q$, $q$Merges accepted amendments into a single final consolidated motion document.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Live convention tools$q$, $q$Supports agendas, speaking lists, roll calls, and live voting during in-person sessions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Projector display mode$q$, $q$Full-screen mode designed for displaying motions and votes on venue screens.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Multi-tenant architecture$q$, $q$One installation can serve multiple separate organizations or branches independently.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Single sign-on support$q$, $q$Integrates with organizational SSO systems for larger member organizations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Free and open source with source code publicly available$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Over a decade of production use by major political and civil-society organizations$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Handles the full motion lifecycle from submission to live voting$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Privacy-conscious with no trackers and EU-based hosting options$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Multi-tenant design suits federated organizations with many branches$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Requires self-hosting expertise or a paid hosting arrangement to run smoothly$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Interface and documentation are heavily oriented toward German political processes$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Smaller niche audience means less third-party documentation and community support$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Limited to German, English, and French language support$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Professional support and hosting costs are hourly rather than fixed, making budgeting less predictable$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$What is motion.tools / Antragsgrün used for?$q$, $q$It is software for managing motions, amendments, and candidacies at conferences and general assemblies, used by political parties, unions, and NGOs.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Is Antragsgrün free?$q$, $q$Yes, it is open-source software under the AGPL license and can be self-hosted for free; paid hosting and support are optional add-ons billed hourly.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Who created Antragsgrün?$q$, $q$It was created in 2012 by developer Tobias Hößl for the Bavarian state branch of Alliance 90/The Greens.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Is motion.tools related to usemotion.com?$q$, $q$No, they are completely unrelated products; motion.tools manages conference motions and amendments, while usemotion.com is an AI calendar and task management app.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$What organizations use Antragsgrün?$q$, $q$Users include the European Youth Forum, the German and European Green Party, Volt Europa, and the National Council of German Women's Organizations, among others.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$What languages does Antragsgrün support?$q$, $q$It is available in German, English, and French.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Political party conventions$q$, $q$Parties use Antragsgrün to manage motions, amendments, and voting at state and national delegate conferences.$q$, $q$Political parties$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$NGO and union general assemblies$q$, $q$Membership organizations run their annual assembly's motion and amendment process through the platform.$q$, $q$NGOs and unions$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Hybrid and in-person convention operations$q$, $q$Organizers use the live speaking-list, roll-call, and projector features to run in-person sessions smoothly.$q$, $q$Convention and assembly organizers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Self-hosted (Open Source)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code on GitHub","Motion, amendment, and candidacy management","Live convention tools","Self-managed hosting"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$Managed hosting and support$q$, $q$Custom, billed hourly$q$, $q$Hourly/custom$q$, NULL, $q$["Professional hosting","Technical support","Custom feature development"]$q$::jsonb, 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$motion.tools, widely known by its German name Antragsgrün, is open-source software for managing motions, amendments, and candidacies at conferences and general assemblies. It was created in 2012 by developer Tobias Hößl for the Bavarian Green Party to simplify motion handling at state delegate conferences, and has since grown into a widely used platform for political parties, unions, and NGOs across Europe.$q$, $q$The software has been actively developed for more than a decade and is now on its 4.x release series. It moved from a single-organization model to a multi-tenant architecture (Antragsgrün 2) so one central installation can serve many separate organizations, a design that remains core to the platform today.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Antragsgrün manages the complete motion lifecycle: submission of motions, amendments, and candidacies; commenting and discussion; automated PDF, spreadsheet, and text exports using customizable templates; and merging accepted amendments into a final consolidated document.$q$, $q$For in-person and hybrid conventions, it also supports live convention operations, including agendas, speaking lists, roll calls, live voting, and a full-screen projector display mode, alongside administrative tools like email notifications, configurable submission policies, and single sign-on for larger organizations.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Antragsgrün is free and open source (AGPL license) and can be self-hosted on an organization's own servers at no cost, with source code available on GitHub. Organizations can also spin up a temporary test instance without providing contact information.$q$, $q$For organizations that don't want to self-host, the project offers optional professional hosting, support, and custom feature development billed on an hourly basis, with servers primarily located in the EU and US hosting available on request.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('2c846e33-a0ef-4fe5-b290-203fbdef22b6', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Peer-to-peer recognition$q$, $q$Employees give each other public recognition tied to monetary rewards from individual or company budgets.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Redeemable rewards$q$, $q$Recognition amounts can be redeemed for gift cards, charitable donations, or company swag.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Employee surveys and pulse feedback$q$, $q$Measures engagement and sentiment through regular pulse surveys.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Manager coaching and one-on-ones$q$, $q$Tools to support structured one-on-one meetings between managers and employees.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Company-wide social feed$q$, $q$Visible feed of recognition and announcements across the organization.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Service anniversaries and milestones$q$, $q$Automated celebrations for work anniversaries and other milestones.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$HR program administration$q$, $q$Runs additional HR initiatives like wellness programs or swag stores from one platform.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$HRIS and workplace integrations$q$, $q$Integrates with existing HR systems, Slack, and Microsoft Teams.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Ties recognition to tangible, redeemable monetary rewards$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Encourages peer-to-peer culture, not just top-down manager recognition$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Expanded feature set covers surveys and broader HR programs, not just recognition$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Integrates into existing workplace tools like Slack and Teams$q$, 3);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Established company with over a decade in the recognition-software space$q$, 4);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$No public pricing, requiring a sales conversation to get a quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Cost can add up for larger organizations depending on modules enabled$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Primarily English-language, limiting appeal for multilingual global teams$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Effectiveness depends heavily on sustained employee adoption and engagement$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Some smaller competitors may offer simpler pricing for budget-conscious teams$q$, 4);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$What is Motivosity used for?$q$, $q$Motivosity is an employee recognition and engagement platform that lets coworkers give each other public recognition tied to monetary rewards, alongside surveys and HR program tools.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$How much does Motivosity cost?$q$, $q$Motivosity uses custom pricing, typically charged per employee per month, and requires contacting sales for a quote since pricing is not published publicly.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Who founded Motivosity?$q$, $q$Motivosity was founded in 2013 by Scott Johnson and is headquartered in Lehi, Utah.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Can Motivosity recognition be redeemed for real rewards?$q$, $q$Yes, recognition given through Motivosity is tied to monetary value that recipients can redeem for gift cards, charitable donations, or company merchandise.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Does Motivosity integrate with other workplace tools?$q$, $q$Yes, it integrates with HR information systems, Slack, and Microsoft Teams.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Who are Motivosity's main competitors?$q$, $q$Its main competitors include Bonusly, Nectar, Kudos, Achievers, and Workhuman.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Company-wide peer recognition programs$q$, $q$HR teams roll out Motivosity so employees can recognize each other's contributions with redeemable rewards.$q$, $q$HR and people operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Measuring engagement and sentiment$q$, $q$Organizations use built-in surveys and pulse feedback to track employee engagement over time.$q$, $q$People analytics and HR leaders$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Reducing turnover through appreciation culture$q$, $q$Companies use consistent recognition and milestone celebrations to improve retention.$q$, $q$Mid-sized to large companies$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$Custom$q$, $q$Contact sales$q$, $q$Per employee per month, custom quote$q$, NULL, $q$["Peer-to-peer recognition with redeemable rewards","Employee surveys and pulse feedback","Manager one-on-one tools","HR program administration","HRIS, Slack, and Teams integrations"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Motivosity is an employee recognition and engagement platform founded in 2013 by Scott Johnson and headquartered in Lehi, Utah. It centers on peer-to-peer recognition, letting coworkers publicly thank each other and attach small monetary rewards funded from individual or company recognition budgets.$q$, $q$The company has grown past 80 employees and has appeared on the Inc. 5000 list of fastest-growing private companies, expanding from a pure recognition tool into a broader employee engagement and HR programs platform.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Recognition on Motivosity is tied to real monetary value that recipients can redeem for gift cards, donations, or company merchandise, and recognition activity is visible across the organization to reinforce a culture of appreciation.$q$, $q$The platform also includes employee surveys and pulse feedback tools, one-on-one meeting support for managers, service anniversary celebrations, and administration for running additional HR programs, with integrations into HRIS systems, Slack, and Microsoft Teams.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('abfa9c4a-e2db-41e9-9dbd-a6c6c0f65814', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Motivosity does not publish pricing on its website; pricing is entirely custom and quoted per company after a sales consultation.$q$, $q$Cost typically scales per employee per month and depends on company size and which modules, such as recognition, surveys, or additional HR program tools, are included in the subscription.$q$]::text[], 2);
